import React, { useEffect, useState } from 'react';
import { Page } from '../components/Layout';
import { getCustomerBookings, getId, updateBookingStatus } from '../services/authService';

export default function CustomerBookingsPage() {
  const [bookings, setBookings] = useState([]);
  const [error, setError] = useState('');

  useEffect(() => {
    const load = async () => {
      try {
        const data = await getCustomerBookings(getId());
        setBookings(data.bookings || []);
      } catch (err) {
        setError('Unable to load your bookings right now.');
      }
    };

    load();
  }, []);

  const cancelBooking = async (bookingId) => {
    try {
      const data = await updateBookingStatus(bookingId, 'Cancelled');
      if (data.success) {
        setBookings((current) =>
          current.map((booking) =>
            booking.id === bookingId
              ? { ...booking, status: 'Cancelled', payment: 'Cancelled' }
              : booking
          )
        );
      }
    } catch (err) {
      setError('Unable to cancel booking.');
    }
  };

  return (
    <Page title="My Bookings" subtitle="Track booking requests and approval status.">
      {error && <div className="alert error">{error}</div>}
      <div className="tableCard">
        <table>
          <thead>
            <tr>
              <th>Car</th>
              <th>Booking ID</th>
              <th>From</th>
              <th>To</th>
              <th>Days</th>
              <th>Price</th>
              <th>Status</th>
              <th>Payment</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {bookings.length === 0 && (
              <tr>
                <td colSpan="9">No bookings found.</td>
              </tr>
            )}
            {bookings.map((booking) => (
              <tr key={booking.id}>
                <td>{booking.car}</td>
                <td>{booking.id}</td>
                <td>{booking.from}</td>
                <td>{booking.to}</td>
                <td>{booking.days}</td>
                <td>₹{Number(booking.price || 0).toLocaleString()}</td>
                <td><span className={`status ${booking.status?.toLowerCase()}`}>{booking.status}</span></td>
                <td>{booking.payment}</td>
                <td>
                  {booking.status === 'Pending' ? (
                    <button className="button danger small" onClick={() => cancelBooking(booking.id)}>
                      Cancel
                    </button>
                  ) : (
                    <span className="muted">No action</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </Page>
  );
}
